   153→class PointsDataGroupedByDayMapper {
   154→  public static getMappedData(
   155→    groupedData: Array<{
   156→      date: string;
   157→      items: propsItemsListCardTransition[];
   158→    }>,
   159→    showLabels = true,
   160→  ): propsItemsListCardTransition[] {
   161→    if (!groupedData || groupedData.length === 0) return [];
   162→
   163→    return groupedData.flatMap(({ date: label, items }) =>
   164→      (items ?? []).map((item, index) => ({
   165→        ...item,
   166→        label,
   167→        showLabel: showLabels ? index === 0 : false,
   168→      })),
   169→    ) as propsItemsListCardTransition[];
   170→  }
   171→}
